/**
 * Budget.jsx
 * ─────────────────────────────────────────────────────────────
 * Página de análisis financiero inteligente.
 * Muestra: categoría dominante, desglose visual, resumen
 * y recomendaciones personalizadas basadas en los datos reales.
 */

import { useMemo }                     from 'react'
import { useTransactions }             from '../hooks/useTransactions'
import { formatCurrency }              from '../utils/formatCurrency'
import styles                          from './Budget.module.css'

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠',
  salud: '💊', entretenimiento: '🎬', educación: '📚',
  ropa: '👕', otros: '📦',
}

/**
 * generateRecommendations
 * ─────────────────────────────────────────────────────────────
 * Motor de análisis financiero.
 * Analiza el resumen real del usuario y devuelve un array
 * de recomendaciones priorizadas por severidad.
 *
 * @param {object} summary    — { totalIncome, totalExpense, balance, byCategory }
 * @param {Array}  transactions — lista completa de transacciones
 * @returns {Array} recomendaciones con { type, icon, title, desc }
 */
const generateRecommendations = (summary, transactions) => {
  if (!summary || !transactions.length) return []

  const { totalIncome, totalExpense, balance, byCategory } = summary
  const recs = []

  // ── 1. Balance negativo (crítico) ────────────────────────
  if (balance < 0) {
    recs.push({
      type:  'danger',
      icon:  '🚨',
      title: 'Déficit detectado',
      desc:  `Estás gastando ${formatCurrency(Math.abs(balance))} más de lo que ingresas. Revisa los gastos de "${Object.entries(byCategory).sort((a,b) => b[1]-a[1])[0]?.[0] || 'mayor categoría'}" que es tu gasto más alto.`,
    })
  }

  // ── 2. Tasa de ahorro ────────────────────────────────────
  if (totalIncome > 0) {
    const rate = Math.round((balance / totalIncome) * 100)
    if (rate >= 30) {
      recs.push({
        type:  'success',
        icon:  '🏆',
        title: `Ahorro del ${rate}% — nivel excelente`,
        desc:  'Superas la regla del 20%. Considera diversificar en fondos de inversión o CDTs para hacer crecer ese excedente.',
      })
    } else if (rate >= 20) {
      recs.push({
        type:  'success',
        icon:  '✅',
        title: `Ahorro del ${rate}% — vas bien`,
        desc:  'Cumples la regla del 20/30/50. Mantén la disciplina y podrías alcanzar el 30% reduciendo gastos en entretenimiento.',
      })
    } else if (rate >= 10) {
      recs.push({
        type:  'warning',
        icon:  '💡',
        title: `Ahorro del ${rate}% — puede mejorar`,
        desc:  `Solo estás ahorrando ${formatCurrency(balance)} al mes. La meta es el 20%. Necesitas reducir gastos en ${formatCurrency(Math.max(0, totalExpense * 0.1))} mensuales.`,
      })
    } else if (rate > 0) {
      recs.push({
        type:  'warning',
        icon:  '⚠️',
        title: `Ahorro del ${rate}% — muy bajo`,
        desc:  'Menos del 10% de ahorro es riesgoso ante imprevistos. Establece un presupuesto estricto para los próximos 30 días.',
      })
    }
  }

  // ── 3. Categoría dominante (>40% del gasto) ─────────────
  if (byCategory && Object.keys(byCategory).length > 0) {
    const [topCat, topAmt] = Object.entries(byCategory).sort((a, b) => b[1] - a[1])[0]
    const pct = totalExpense ? Math.round((topAmt / totalExpense) * 100) : 0
    if (pct > 40) {
      recs.push({
        type:  'warning',
        icon:  CATEGORY_EMOJI[topCat] || '📦',
        title: `${pct}% de tus gastos van a "${topCat}"`,
        desc:  `Alta concentración en una categoría es una señal de alerta. Evalúa si puedes redistribuir ${formatCurrency(topAmt * 0.15)} de ese gasto.`,
      })
    }
  }

  // ── 4. Entretenimiento alto (>25%) ──────────────────────
  const entAmt = byCategory?.entretenimiento || 0
  if (totalExpense > 0 && entAmt / totalExpense > 0.25) {
    recs.push({
      type:  'warning',
      icon:  '🎬',
      title: 'Entretenimiento consume más del 25%',
      desc:  'Considera cancelar suscripciones que no uses, compartir cuentas de streaming o buscar planes familiares.',
    })
  }

  // ── 5. Sin ingresos registrados ──────────────────────────
  if (totalIncome === 0 && totalExpense > 0) {
    recs.push({
      type:  'info',
      icon:  '📥',
      title: 'No tienes ingresos registrados',
      desc:  'Sin ingresos no puedes calcular tu tasa de ahorro real. Registra tu salario y otras entradas para obtener un análisis completo.',
    })
  }

  // ── 6. Pocas transacciones (análisis limitado) ───────────
  if (transactions.length < 5) {
    recs.push({
      type:  'info',
      icon:  '📊',
      title: 'Pocos datos para un análisis completo',
      desc:  `Con solo ${transactions.length} transacción(es), las recomendaciones son limitadas. Registra al menos un mes de movimientos para análisis precisos.`,
    })
  }

  // ── Default: todo bien ───────────────────────────────────
  if (recs.length === 0) {
    recs.push({
      type:  'success',
      icon:  '🌟',
      title: 'Tus finanzas están en buen estado',
      desc:  'Mantén el ritmo. Define metas de ahorro mensuales para seguir mejorando y considera crear un fondo de emergencia de 3–6 meses de gastos.',
    })
  }

  return recs
}

export default function Budget() {
  const { transactions, summary, loading, error } = useTransactions()

  const {
    totalIncome  = 0,
    totalExpense = 0,
    balance      = 0,
    byCategory   = {},
    count        = 0,
  } = summary || {}

  const recommendations = useMemo(
    () => generateRecommendations(summary, transactions),
    [summary, transactions]
  )

  const sortedCategories = Object.entries(byCategory).sort((a, b) => b[1] - a[1])
  const topCategory      = sortedCategories[0]
  const savingsRate      = totalIncome > 0 ? Math.round((balance / totalIncome) * 100) : null

  if (error) return <div className="feedback feedback-error mt-4">⚠️ {error}</div>

  return (
    <div className={styles.page}>
      {/* Encabezado */}
      <div className={`${styles.pageHeader} animate-fade-up`}>
        <div>
          <h1 className={styles.pageTitle}>Análisis financiero</h1>
          <p className={styles.pageSubtitle}>Diagnóstico basado en tus movimientos reales</p>
        </div>
      </div>

      {/* ── Categoría dominante ─────────────────────── */}
      {topCategory && !loading && (
        <div className={`card ${styles.topCard} animate-fade-up delay-1 mb-6`}>
          <div className={styles.topLeft}>
            <span className={styles.topEmoji}>{CATEGORY_EMOJI[topCategory[0]] || '📦'}</span>
            <div>
              <p className="label">En qué más gastas</p>
              <p className={styles.topCatName}>
                {topCategory[0].charAt(0).toUpperCase() + topCategory[0].slice(1)}
              </p>
              <p className={styles.topCatAmt}>
                {formatCurrency(topCategory[1])}
                {totalExpense > 0 && (
                  <span className={styles.topCatPct}>
                    {' '}— {Math.round((topCategory[1] / totalExpense) * 100)}% del total de gastos
                  </span>
                )}
              </p>
            </div>
          </div>
          {savingsRate !== null && (
            <div className={styles.topRight}>
              <p className="label">Tasa de ahorro</p>
              <p className={`${styles.savingsRate} font-display ${savingsRate >= 20 ? styles.rateGood : savingsRate >= 0 ? styles.rateOk : styles.rateBad}`}>
                {savingsRate}%
              </p>
              <p className={styles.savingsLabel}>
                {savingsRate >= 20 ? 'Excelente' : savingsRate >= 10 ? 'Mejorable' : savingsRate >= 0 ? 'Bajo' : 'Déficit'}
              </p>
            </div>
          )}
        </div>
      )}

      <div className={`grid-2 mb-6`}>
        {/* ── Desglose por categoría ─────────────────── */}
        <div className={`card animate-fade-up delay-2`}>
          <div className="card-header">
            <span className="label">Desglose de gastos</span>
          </div>

          {loading ? (
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
              {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height:32 }} />)}
            </div>
          ) : sortedCategories.length === 0 ? (
            <p style={{ color:'var(--text-tertiary)', fontSize:'0.875rem' }}>Sin gastos registrados.</p>
          ) : (
            <ul className={styles.catList}>
              {sortedCategories.map(([cat, amt], i) => {
                const pct = totalExpense ? Math.round((amt / totalExpense) * 100) : 0
                return (
                  <li key={cat} className={`${styles.catRow} animate-fade-up delay-${i + 1}`}>
                    <div className={styles.catMeta}>
                      <span className={styles.catLabel}>
                        {CATEGORY_EMOJI[cat] || '📦'}{' '}
                        {cat.charAt(0).toUpperCase() + cat.slice(1)}
                      </span>
                      <div className={styles.catRight}>
                        <span className={styles.catAmt}>{formatCurrency(amt)}</span>
                        <span className={styles.catPct}>{pct}%</span>
                      </div>
                    </div>
                    <div className={styles.barBg}>
                      <div
                        className={styles.barFill}
                        style={{ width: `${pct}%` }}
                        role="progressbar"
                        aria-valuenow={pct}
                        aria-valuemin={0}
                        aria-valuemax={100}
                      />
                    </div>
                  </li>
                )
              })}
            </ul>
          )}
        </div>

        {/* ── Resumen financiero ─────────────────────── */}
        <div className={`card animate-fade-up delay-3`}>
          <div className="card-header">
            <span className="label">Resumen financiero</span>
          </div>

          <ul className={styles.summaryList}>
            {[
              { label: '💚 Ingresos totales',  value: formatCurrency(totalIncome),  cls: styles.valPos },
              { label: '🔴 Gastos totales',    value: formatCurrency(totalExpense), cls: styles.valNeg },
              { label: '⚖️ Balance neto',      value: formatCurrency(balance),      cls: balance >= 0 ? styles.valPos : styles.valNeg, bold: true },
              { label: '💾 Tasa de ahorro',    value: savingsRate !== null ? `${savingsRate}%` : '—', cls: '' },
              { label: '📋 Transacciones',     value: count, cls: '' },
            ].map(({ label, value, cls, bold }) => (
              <li key={label} className={`${styles.summaryRow} ${bold ? styles.summaryBold : ''}`}>
                <span className={styles.summaryLabel}>{label}</span>
                <span className={`${styles.summaryValue} ${cls}`}>{value}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>

      {/* ── Recomendaciones ───────────────────────────── */}
      <div className={`card animate-fade-up delay-4`}>
        <div className="card-header">
          <span className="label">Recomendaciones personalizadas</span>
          <span className={styles.recCount}>{recommendations.length} sugerencia{recommendations.length !== 1 ? 's' : ''}</span>
        </div>

        <div className={styles.recGrid}>
          {recommendations.map((r, i) => (
            <div
              key={i}
              className={`${styles.rec} ${styles[`rec_${r.type}`]} animate-fade-up delay-${i + 1}`}
            >
              <span className={styles.recIcon}>{r.icon}</span>
              <div>
                <p className={styles.recTitle}>{r.title}</p>
                <p className={styles.recDesc}>{r.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
